# Coin Change — O(amount * coins) time, O(amount) space
# KEY INSIGHT: dp[i] = min coins to make amount i
# For each amount, try subtracting each coin and take minimum

def coinChange(coins, amount):
    dp = [float('inf')] * (amount + 1)
    dp[0] = 0  # 0 coins needed to make amount 0

    for i in range(1, amount + 1):
        for coin in coins:
            if coin <= i:
                dp[i] = min(dp[i], dp[i - coin] + 1)

    return dp[amount] if dp[amount] != float('inf') else -1
# WHY unbounded: same coin can be used multiple times (no 'used' tracking)
# PITFALL: check for inf at end — some amounts may be unreachable
